using System.ComponentModel;
using System.Text.RegularExpressions;
using Microsoft.Extensions.AI;
using OpenAI;

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to run this agent.");

var modelId = "gpt-4o-mini-2024-07-18";

IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// Define tools available to the agent
var searchTool = AIFunctionFactory.Create(ResearchTools.SearchWeb);
var takeNoteTool = AIFunctionFactory.Create(ResearchTools.TakeNote);
var getNotesTool = AIFunctionFactory.Create(ResearchTools.GetNotes);

var tools = new AITool[] { searchTool, takeNoteTool, getNotesTool };

// Get the research topic from the user
Console.Write("Enter a topic to research: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrEmpty(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\nResearching: {topic}\n");

var systemPrompt = """
    You are a research agent. Your job is to research a topic thoroughly using the available tools.

    Follow this process:
    1. Search the web for information about the topic (perform 2-3 searches with different angles)
    2. Take notes on the key findings from each search
    3. After gathering enough information, retrieve your notes and provide a comprehensive summary

    Always take notes on important findings before moving to the next search.
    End with a well-structured summary that synthesizes all your research.
    """;

var messages = new List<ChatMessage>
{
    new(ChatRole.System, systemPrompt),
    new(ChatRole.User, $"Research the following topic and provide a summary: {topic}"),
};

var options = new ChatOptions
{
    Tools = tools,
    Temperature = 0f,
    MaxOutputTokens = 2048,
};

// Agent loop with iteration limit
const int maxIterations = 15;
var iteration = 0;

while (iteration < maxIterations)
{
    iteration++;
    var response = await chatClient.GetResponseAsync(messages, options);

    // Add all response messages to the conversation
    foreach (var msg in response.Messages)
    {
        messages.Add(msg);
    }

    // Check if the model made tool calls
    var toolCalls = response.Messages
        .SelectMany(m => m.Contents.OfType<FunctionCallContent>())
        .ToList();

    if (toolCalls.Count == 0)
    {
        // No tool calls — the agent is done; print final response
        var finalText = response.Messages
            .SelectMany(m => m.Contents.OfType<TextContent>())
            .Select(t => t.Text)
            .FirstOrDefault();

        if (!string.IsNullOrEmpty(finalText))
        {
            Console.WriteLine("═══ Research Summary ═══\n");
            Console.WriteLine(finalText);
        }
        break;
    }

    // Execute tool calls and add results
    foreach (var toolCall in toolCalls)
    {
        Console.WriteLine($"  [Tool] {toolCall.Name}({FormatArgs(toolCall.Arguments)})");

        var result = await toolCall.InvokeAsync(tools, cancellationToken: default);
        messages.Add(new ChatMessage(ChatRole.Tool,
        [
            new FunctionResultContent(toolCall.CallId, result),
        ]));
    }
}

if (iteration >= maxIterations)
{
    Console.WriteLine("\n[Agent reached iteration limit]");
}

static string FormatArgs(IDictionary<string, object?>? args) =>
    args is null ? "" : string.Join(", ", args.Select(kv => $"{kv.Key}: \"{kv.Value}\""));

